import React from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import Myp8 from './pages/Myp8';
import QuiJeSuis from './pages/QuiJeSuis';
import MesServices from './pages/MesServices';
import MesCompetences from './pages/MesCompetences';
import MesProjets from './pages/MesProjets';
import Contacts from './pages/Contacts';

const App = () => {
  return (
    <Router>
      <Header />
      <Switch>
        <Route exact path="/" component={HomePage} />
        <Route path="/myp8" component={Myp8} />
        <Route path="/qui_je_suis" component={QuiJeSuis} />
        <Route path="/mes_services" component={MesServices} />
        <Route path="/mes_competences" component={MesCompetences} />
        <Route path="/mes_projets" component={MesProjets} />
        <Route path="/contacts" component={Contacts} />
      </Switch>
      <Footer />
    </Router>
  );
};

export default App;
